    private List<String> splitWithRespectToParentheses(String query, char delimiter) {
        List<String> result = new ArrayList<String>();
        int parenCount = 0;
        int start = 0;

        for (int i = 0; i < query.length(); i++) {
            char c = query.charAt(i);
            if (c == '(') {
                parenCount++;
            } else if (c == ')') {
                parenCount--;
            } else if (c == delimiter && parenCount == 0) {
                // Only split on delimiter if not inside parentheses
                result.add(query.substring(start, i));
                start = i + 1;
            }
        }

        // Add the last part
        result.add(query.substring(start));

        return result;
    }
}

